#!/bin/bash
# ==================================================
#   Tendo Store - Protected Loader
#   Script asli terenkripsi (gzip+base64), didekode & dijalankan di memory
#   Jangan modifikasi file ini secara manual.
# ==================================================

_TENDO_PAYLOAD=""
_TENDO_SUM="8c0f2125480cd13c40b68196c15f20cadc399c123d233028e9d18da962023649"

# Cek tool wajib
for c in base64 gzip sha256sum bash; do
    command -v "$c" >/dev/null 2>&1 || { echo "[ERROR] Tool '$c' tidak ditemukan di sistem ini."; exit 1; }
done

# Decode ke memory (tmpfs), jangan pernah simpan plaintext permanen
_TMP=$(mktemp -p /dev/shm tendo.XXXXXX 2>/dev/null || mktemp)
trap 'shred -u "$_TMP" 2>/dev/null || rm -f "$_TMP"' EXIT

echo "$_TENDO_PAYLOAD" | base64 -d | gunzip > "$_TMP" 2>/dev/null
if [ $? -ne 0 ] || [ ! -s "$_TMP" ]; then
    echo "[ERROR] Gagal decode script. File rusak atau di-tamper."
    exit 1
fi

# Verifikasi integritas
_CALC_SUM=$(sha256sum "$_TMP" | awk '{print $1}')
if [ "$_CALC_SUM" != "$_TENDO_SUM" ]; then
    echo "[ERROR] Checksum tidak cocok — script telah dimodifikasi. Eksekusi dibatalkan."
    exit 1
fi

chmod +x "$_TMP"
bash "$_TMP" "$@"
_EXIT=$?
exit $_EXIT
